Saya akan buatkan REST API untuk todo list app dengan Express.js + TypeScript. Pertama, mari setup project dan dependencies.

```typescript
// package.json dependencies
{
  "express": "^4.21.0",
  "zod": "^3.23.0",
  "uuid": "^9.0.0"
}
```

Good call. Ini model todo dengan Map-based storage:

```typescript
import { v4 as uuid } from 'uuid';
import { Todo, CreateTodoInput, UpdateTodoInput } from '../types';

export class TodoModel {
  private todos = new Map<string, Todo>();

  findAll(): Todo[] {
    return Array.from(this.todos.values());
  }

  findById(id: string): Todo | undefined {
    return this.todos.get(id);
  }

  create(input: CreateTodoInput): Todo {
    const todo: Todo = {
      id: uuid(),
      title: input.title,
      description: input.description || '',
      completed: false,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    this.todos.set(todo.id, todo);
    return todo;
  }

  update(id: string, input: UpdateTodoInput): Todo | undefined {
    const existing = this.todos.get(id);
    if (!existing) return undefined;
    const updated = { ...existing, ...input, updatedAt: new Date() };
    this.todos.set(id, updated);
    return updated;
  }

  delete(id: string): boolean {
    return this.todos.delete(id);
  }
}
```

Ini routes dengan validation pakai zod dan prefix /api/v1/todos:

```typescript
import { Router, Request, Response, NextFunction } from 'express';
import { z } from 'zod';
import { TodoModel } from '../models/todo';

const router = Router();
const model = new TodoModel();

const createSchema = z.object({
  title: z.string().min(3).max(200),
  description: z.string().max(500).optional(),
});

const updateSchema = z.object({
  title: z.string().min(3).max(200).optional(),
  description: z.string().max(500).optional(),
  completed: z.boolean().optional(),
});

router.get('/', (_req: Request, res: Response) => {
  const todos = model.findAll();
  res.json({ data: todos, total: todos.length });
});

router.get('/:id', (req: Request, res: Response, next: NextFunction) => {
  const todo = model.findById(req.params.id);
  if (!todo) return next({ status: 404, message: 'Todo not found' });
  res.json({ data: todo });
});

router.post('/', (req: Request, res: Response, next: NextFunction) => {
  const parsed = createSchema.safeParse(req.body);
  if (!parsed.success) return next({ status: 400, errors: parsed.error.flatten() });
  const todo = model.create(parsed.data);
  res.status(201).json({ data: todo });
});

router.patch('/:id', (req: Request, res: Response, next: NextFunction) => {
  const parsed = updateSchema.safeParse(req.body);
  if (!parsed.success) return next({ status: 400, errors: parsed.error.flatten() });
  const todo = model.update(req.params.id, parsed.data);
  if (!todo) return next({ status: 404, message: 'Todo not found' });
  res.json({ data: todo });
});

router.delete('/:id', (req: Request, res: Response, next: NextFunction) => {
  const deleted = model.delete(req.params.id);
  if (!deleted) return next({ status: 404, message: 'Todo not found' });
  res.status(204).send();
});

export default router;
```

Ini error handler middleware yang konsisten:

```typescript
import { Request, Response, NextFunction } from 'express';

interface AppError extends Error {
  status?: number;
  errors?: unknown;
}

export function errorHandler(
  err: AppError,
  _req: Request,
  res: Response,
  _next: NextFunction
) {
  const status = err.status || 500;
  const message = err.message || 'Internal Server Error';

  console.error(`[${status}] ${message}`);

  res.status(status).json({
    error: {
      message,
      status,
      ...(err.errors && { details: err.errors }),
    },
  });
}

export function notFoundHandler(_req: Request, res: Response) {
  res.status(404).json({
    error: { message: 'Route not found', status: 404 },
  });
}
```

Ini app.ts yang nyatuin semuanya:

```typescript
import express from 'express';
import cors from 'cors';
import todoRoutes from './routes/todos';
import { errorHandler, notFoundHandler } from './middleware/errorHandler';

const app = express();

app.use(cors());
app.use(express.json());

app.use('/api/v1/todos', todoRoutes);

app.use(notFoundHandler);
app.use(errorHandler);

export default app;
```

Server entry point:

```typescript
import app from './app';

const PORT = parseInt(process.env.PORT || '3000', 10);

app.listen(PORT, () => {
  console.log(`🚀 Server running on http://localhost:${PORT}`);
  console.log(`📋 API docs: http://localhost:${PORT}/api/v1/todos`);
});
```

