Tambahin filter di route GET /:

```typescript
router.get('/', (req: Request, res: Response) => {
  let todos = model.findAll();

  // Filter by completion status
  if (req.query.completed !== undefined) {
    const isCompleted = req.query.completed === 'true';
    todos = todos.filter(t => t.completed === isCompleted);
  }

  // Search by title
  if (typeof req.query.search === 'string') {
    const keyword = req.query.search.toLowerCase();
    todos = todos.filter(t => t.title.toLowerCase().includes(keyword));
  }

  res.json({ data: todos, total: todos.length });
});
```

Tambahin rate limiting di app.ts:

```typescript
import rateLimit from 'express-rate-limit';

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 menit
  max: 100, // maksimal 100 request per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: { message: 'Too many requests', status: 429 } },
});

app.use('/api/', limiter);
```

Tambahkan ke dependencies: `pnpm add express-rate-limit`
